409		/**
410		 * Process prefixes during fiscal year change
411		 * This applies stored prefixes from globalFiscalYearPrefixes to the chain and store settings
412		 * 
413		 * @param int $chainID
414		 * @param string|null $fiscalYear Optional fiscal year in YYYY-MM-DD format. If null, tomorrow's date will be used to calculate it.
415		 * @return array Status of the operation
416		 */
417		public function applyFiscalYearPrefixes($chainID, $fiscalYear = null) {
418			return $this->dbManager->executeWithRetry(function () use ($chainID, $fiscalYear) {
419				$this->logger->info("Applying fiscal year prefixes for chain: {$chainID}" . ($fiscalYear ? " and fiscal year: {$fiscalYear}" : ""));
420				
421				$listOfChainsTable = Constants::getGlobalTableName("listOfChains");
422				$chainSettingsTable = Constants::getGlobalTableName("chainSettings");
423				$listOfStoresTable = Constants::getGlobalTableName("listOfStores");
424				$fiscalYearPrefixesTable = Constants::getGlobalTableName("fiscalYearPrefixes"); // This will resolve to globalFiscalYearPrefixes
425				
426				// Define currentYear variable for use in both if and later code
427				$currentYear = Carbon::tomorrow()->year;
428				
429				// Only calculate fiscal year if not provided
430				if ($fiscalYear === null) {
431					// Get chain fiscal year start date (format: mmdd)
432					$chainSettings = DB::table($chainSettingsTable)
433						->where('chainRefID', $chainID)
434						->select('fiscalYearStart')
435						->first();
436					
437					if (!$chainSettings) {
438						$this->logger->error("Chain settings not found for chain ID: {$chainID}");
439						return [
440							'status' => false,
441							'message' => "Chain settings not found"
442						];
443					}
444					
445					// Calculate the fiscal year based on tomorrow's date
446					$tomorrow = Carbon::tomorrow();
447					$fiscalStartMMDD = $chainSettings->fiscalYearStart;
448					// Format with a dash between month and day for YYYY-MM-DD format
449					$month = substr($fiscalStartMMDD, 0, 2);
450					$day = substr($fiscalStartMMDD, 2, 2);
451					$fiscalYear = $currentYear . '-' . $month . '-' . $day;
452				}
453	
454				$fiscalResetDate = $fiscalYear;
455				DB::table($listOfStoresTable)
456					->where('chainID', $chainID)
457					->update([
458						'storeTransactionResetDate' => $fiscalResetDate
459					]);
460				$this->logger->info("Applied fiscal reset date {$fiscalResetDate} to all stores for chain {$chainID}");
461	
462				// Get active prefixes for this chain and fiscal year
463				$activePrefixes = DB::table($fiscalYearPrefixesTable)
464					->where('chainID', $chainID)
465					->where('fiscalYear', $fiscalYear)
466					->where('isActive', true)
467					->get();
468	
469				$this->logger->info("Active prefixes for chain ID: {$chainID} and fiscal year: {$fiscalYear}");
470				$this->logger->info("Active prefixes: " . json_encode($activePrefixes));
471				
472				// Check if there are no active prefixes (handle both Collection and array)
473				if (empty($activePrefixes) || (is_object($activePrefixes) && method_exists($activePrefixes, 'isEmpty') && $activePrefixes->isEmpty())) {
474					$this->logger->notice("No active prefixes found for chain ID: {$chainID} and fiscal year: {$fiscalYear}");
475					// Use default prefixes
476					// Example: OR26 | RF26
477					$nextYear = $currentYear + 1;
478					$prefixYears = substr($nextYear, -2);
479					$defaultPrefixes = [
480						'customOrderPrefix' => "OR{$prefixYears}",
481						'customRefundOrderPrefix' => "RF{$prefixYears}"
482					];
483					
484					// Update chain settings with default prefixes
485					DB::table($listOfChainsTable)
486						->where('chainID', $chainID)
487						->update([
488							'customOrderPrefix' => $defaultPrefixes['customOrderPrefix'],
489							'customRefundOrderPrefix' => $defaultPrefixes['customRefundOrderPrefix']
490						]);
491					// return
492					return [
493						'status' => true,
494						'message' => "Default prefixes applied for chain ID: {$chainID}"
495					];
496				}
497				
498				$this->logger->info("Found " . count($activePrefixes) . " active prefixes to apply");
499					
500				// Apply chain level prefixes if found
501				$chainPrefixes = null;
502				// Handle both Collection and array
503				if (is_object($activePrefixes) && method_exists($activePrefixes, 'where')) {
504					$chainPrefixes = $activePrefixes->where('storeID', 0)->first();
505				} else {
506					// Handle as array
507					foreach ($activePrefixes as $prefix) {
508						if ($prefix->storeID == 0) {
509							$chainPrefixes = $prefix;
510							break;
511						}
512					}
513				}
514				if ($chainPrefixes) {
515					$this->logger->info("Applying chain-level prefixes for chain ID: {$chainID}");
516					
517					DB::table($listOfChainsTable)
518						->where('chainID', $chainID)
519						->update([
520							'customOrderPrefix' => $chainPrefixes->customOrderPrefix,
521							'customRefundOrderPrefix' => $chainPrefixes->customRefundOrderPrefix
522						]);
523				}
524				// check if non chain level prefixes are present (store ID non 0)
525				$nonChainPrefixes = [];
526				
527				// Handle both Collection and array
528				if (is_object($activePrefixes) && method_exists($activePrefixes, 'where')) {
529					$nonChainPrefixes = $activePrefixes->where('storeID', '!=', 0);
530				} else {
531					// Handle as array
532					foreach ($activePrefixes as $prefix) {
533						if ($prefix->storeID != 0) {
534							$nonChainPrefixes[] = $prefix;
535						}
536					}
537				}
538				
539				if (empty($nonChainPrefixes) || (is_object($nonChainPrefixes) && method_exists($nonChainPrefixes, 'isEmpty') && $nonChainPrefixes->isEmpty())) {
540					$this->logger->info("No non-chain level prefixes found for chain ID: {$chainID}");
541					// return
542					return [
543						'status' => true,
544						'message' => "Prefix applied successfully for chain ID: {$chainID}"
545					];
546				}
547	
548				$this->logger->info("Found " . count($nonChainPrefixes) . " non-chain level prefixes to apply");
549				$storeCount = 0;
550				foreach ($nonChainPrefixes as $prefix) {
551					DB::table($listOfStoresTable)
552						->where('storeID', $prefix->storeID)
553						->update([
554							'customStoreOrderPrefix' => $prefix->customOrderPrefix,
555							'refundCustomStoreOrderPrefix' => $prefix->customRefundOrderPrefix,
556							'NCCustomStoreOrderPrefix' => $prefix->NCCustomStoreOrderPrefix,
557							'NCRefundCustomStoreOrderPrefix' => $prefix->NCRefundCustomStoreOrderPrefix,
558							'RWICustomStoreOrderPrefix' => $prefix->RWICustomStoreOrderPrefix
559						]);
560					$storeCount++;
561				}
562				
563				$this->logger->info("Saved fiscal year prefixes for chain {$chainID}: 1 chain record and {$storeCount} store records");
564				
565				return [
566					'status' => true,
567					'message' => "Saved fiscal year prefixes for chain {$chainID}",
568					'chainCount' => 1,
569					'storeCount' => $storeCount
570				];
571			});
572		}
