575		 * Reset server-generated invoice sequence data for the upcoming fiscal year.
576		 *
577		 * For chains using generateInvoiceNumberFromServer, invoiceSequence rows are keyed by resetDate.
578		 * Seeding the new resetDate rows with lastInvoiceNumber = 0 guarantees the first invoice after rollover becomes 1.
579		 *
580		 * @param int $chainID
581		 * @param string $fiscalResetDate Date in Y-m-d format
582		 * @return array
583		 */
584		public function resetServerGeneratedInvoiceSequences($chainID, $fiscalResetDate) {
585			return $this->dbManager->executeWithRetry(function () use ($chainID, $fiscalResetDate) {
586				$chainSettingsTable = Constants::getGlobalTableName("chainSettings");
587				$listOfStoresTable = Constants::getGlobalTableName("listOfStores");
588				$invoiceSequenceTable = Constants::getChainTableName($chainID, "invoiceSequence");
589	
590				$generateInvoiceNumberFromServer = DB::table($chainSettingsTable)
591					->where('chainRefID', $chainID)
592					->value('generateInvoiceNumberFromServer');
593	
594				if ((int)$generateInvoiceNumberFromServer !== 1) {
595					$this->logger->info("Skipping server invoice sequence reset for chain {$chainID}: generateInvoiceNumberFromServer is disabled");
596					return [
597						'status' => true,
598						'message' => "Server invoice sequence reset skipped for chain {$chainID}"
599					];
600				}
601	
602				if (!Schema::hasTable($invoiceSequenceTable)) {
603					$referenceTableName = Constants::getChainTableName(1, "invoiceSequence");
604					if (!Schema::hasTable($referenceTableName)) {
605						throw new Exception("Reference invoice sequence table missing: {$referenceTableName}");
606					}
607	
608					DB::statement(createTableSchema($referenceTableName, $invoiceSequenceTable));
609					$this->logger->info("Created missing invoice sequence table {$invoiceSequenceTable} for chain {$chainID}");
610				}
611	
612				$stores = DB::table($listOfStoresTable)
613					->where('chainID', $chainID)
614					->where('isActive', 1)
615					->select('storeID')
616					->get();
617	
618				$seededRows = 0;
619				foreach ($stores as $store) {
620					foreach ([0, 1] as $isNoCharge) {
621						foreach ([0, 1] as $isRefund) {
622							$existingRow = DB::table($invoiceSequenceTable)
623								->where('storeID', $store->storeID)
624								->where('isNoCharge', $isNoCharge)
625								->where('isRefund', $isRefund)
626								->where('resetDate', $fiscalResetDate)
627								->first();
628	
629							$payload = [
630								'lastInvoiceNumber' => 0,
631								'updatedAt' => Carbon::now()
632							];
633	
634							if ($existingRow) {
635								DB::table($invoiceSequenceTable)
636									->where('ID', $existingRow->ID)
637									->update($payload);
638							} else {
639								$payload['storeID'] = $store->storeID;
640								$payload['isNoCharge'] = $isNoCharge;
641								$payload['isRefund'] = $isRefund;
642								$payload['resetDate'] = $fiscalResetDate;
643								$payload['createdAt'] = Carbon::now();
644								DB::table($invoiceSequenceTable)->insert($payload);
645							}
646	
647							$seededRows++;
648						}
649					}
650				}
651	
652				$this->logger->info("Seeded {$seededRows} server invoice sequence rows for chain {$chainID} and fiscal reset date {$fiscalResetDate}");
653	
654				return [
655					'status' => true,
656					'message' => "Reset server invoice sequences for chain {$chainID}",
657					'seededRows' => $seededRows
658				];
659			});
660		}
