662		/**
663		 * Save fiscal year prefixes for a chain
664		 * Stores prefixes to be used in a future fiscal year
665		 * 
666		 * @param int $chainID Chain ID
667		 * @param string $fiscalYear Fiscal year in format YYYY-MMDD
668		 * @param array $data Prefix data
669		 * @return array Status of the operation
670		 */
671		public function savePrefixesForFiscalYear($chainID, $fiscalYear, $data) {
672			return $this->dbManager->executeWithRetry(function () use ($chainID, $fiscalYear, $data) {
673				$this->logger->info("Saving custom prefixes for chain: {$chainID}, fiscal year: {$fiscalYear}");
674				
675				$fiscalYearPrefixesTable = Constants::getGlobalTableName("fiscalYearPrefixes");
676				
677				// Validate fiscal year format (YYYY-MM-DD)	
678				if (!preg_match('/^\d{4}-\d{2}-\d{2}$/', $fiscalYear)) {
679					return [
680						'status' => false,
681						'message' => "Invalid fiscal year format. Expected: YYYY-MM-DD"
682					];
683				}
684				
685				$storeID = isset($data['storeID']) ? $data['storeID'] : 0;
686				$listOfStoresTable = Constants::getGlobalTableName('listOfStores');
687				$chainUsesStorePrefixes = DB::table($listOfStoresTable)
688					->where('chainID', $chainID)
689					->where('isActive', 1)
690					->whereNotNull('customStoreOrderPrefix')
691					->where('customStoreOrderPrefix', '!=', '')
692					->exists();
693	
694				if ($chainUsesStorePrefixes && (int) $storeID <= 0) {
695					return [
696						'status' => false,
697						'message' => 'This chain uses store prefixes. Fiscal year prefixes must be saved per store.',
698					];
699				}
700	
701				// Check if the entry already exists
702				$existingEntry = DB::table($fiscalYearPrefixesTable)
703					->where('chainID', $chainID)
704					->where('storeID', $storeID)
705					->where('fiscalYear', $fiscalYear)
706					->first();
707	
708				$storePrefixFields = [
709					'customOrderPrefix' => 'order prefix',
710					'customRefundOrderPrefix' => 'refund prefix',
711					'NCCustomStoreOrderPrefix' => 'no-charge order prefix',
712					'NCRefundCustomStoreOrderPrefix' => 'no-charge refund prefix',
713					'RWICustomStoreOrderPrefix' => 'refund without invoice prefix',
714				];
715	
716				if ($storeID > 0) {
717					foreach ($storePrefixFields as $column => $label) {
718						$value = isset($data[$column]) ? trim($data[$column]) : "";
719						if ($value === "") {
720							continue;
721						}
722	
723						$duplicateQuery = DB::table($fiscalYearPrefixesTable)
724							->where('chainID', $chainID)
725							->where('fiscalYear', $fiscalYear)
726							->where($column, $value)
727							->where('storeID', '>', 0)
728							->where('storeID', '!=', $storeID);
729	
730						$duplicate = $duplicateQuery->first();
731						if (!$duplicate) {
732							continue;
733						}
734	
735						$conflictStore = DB::table($listOfStoresTable)
736							->select('storeName')
737							->where('chainID', $chainID)
738							->where('storeID', $duplicate->storeID)
739							->first();
740	
741						$storeLabel = $conflictStore ? $conflictStore->storeName : "ID {$duplicate->storeID}";
742	
743						return [
744							'status' => false,
745							'message' => "The {$label} '{$value}' is already used by store {$storeLabel} ({$duplicate->storeID}) for fiscal year {$fiscalYear}.",
746						];
747					}
748				}
749				
750				$prefixData = [
751					'chainID' => $chainID,
752					'storeID' => isset($data['storeID']) ? $data['storeID'] : 0,
753					'fiscalYear' => $fiscalYear,
754					'customOrderPrefix' => isset($data['customOrderPrefix']) ? $data['customOrderPrefix'] : null,
755					'customRefundOrderPrefix' => isset($data['customRefundOrderPrefix']) ? $data['customRefundOrderPrefix'] : null,
756					'NCCustomStoreOrderPrefix' => isset($data['NCCustomStoreOrderPrefix']) ? $data['NCCustomStoreOrderPrefix'] : null,
757					'NCRefundCustomStoreOrderPrefix' => isset($data['NCRefundCustomStoreOrderPrefix']) ? $data['NCRefundCustomStoreOrderPrefix'] : null,
758					'RWICustomStoreOrderPrefix' => isset($data['RWICustomStoreOrderPrefix']) ? $data['RWICustomStoreOrderPrefix'] : null,
759					'isActive' => true,
760					'updatedAt' => Carbon::now()
761				];
762				
763				if ($existingEntry) {
764					// Update existing entry
765					$prefixData['updatedAt'] = Carbon::now();
766					
767					// Deactivate all other prefixes for this chain/store combination
768					DB::table($fiscalYearPrefixesTable)
769						->where('chainID', $chainID)
770						->where('storeID', isset($data['storeID']) ? $data['storeID'] : 0)
771						->where('id', '!=', $existingEntry->id)
772						->update(['isActive' => false]);
773						
774					// Update this entry
775					DB::table($fiscalYearPrefixesTable)
776						->where('id', $existingEntry->id)
777						->update($prefixData);
778	
779					$this->ensureFiscalYearStartSetting($chainID, $fiscalYear);
780	
781					return [
782						'status' => true,
783						'message' => "Updated fiscal year prefixes for chain ID: {$chainID}, fiscal year: {$fiscalYear}"
784					];
785				} else {
786					// Insert new entry
787					$prefixData['createdAt'] = Carbon::now();
788					
789					// Deactivate all other prefixes for this chain/store combination
790					DB::table($fiscalYearPrefixesTable)
791						->where('chainID', $chainID)
792						->where('storeID', isset($data['storeID']) ? $data['storeID'] : 0)
793						->update(['isActive' => false]);
794						
795					// Create new entry
796					DB::table($fiscalYearPrefixesTable)->insert($prefixData);
797	
798					$this->ensureFiscalYearStartSetting($chainID, $fiscalYear);
799	
800					return [
801						'status' => true,
802						'message' => "Saved new fiscal year prefixes for chain ID: {$chainID}, fiscal year: {$fiscalYear}"
803					];
804				}
805			});
806		}
