219	    /**
220	     * Process a specific charge type and order type for a store
221	     */
222	    private function processChargeType($chainID, $storeID, $isNoCharge, $isRefund, $storeTransactionResetDate, $chainInvoiceSummaryTable, $invoiceSequenceTable, $dryRun, $force)
223	    {
224	        // Check if sequence already exists
225	        $existingSequence = DB::table($invoiceSequenceTable)
226	            ->where('storeID', $storeID)
227	            ->where('isNoCharge', $isNoCharge)
228	            ->where('isRefund', $isRefund)
229	            ->first();
230	
231	        if ($existingSequence && !$force) {
232	            $this->stats['sequences_skipped']++;
233	            return;
234	        }
235	
236	        // Build query to get max invoice number
237	        // For refunds: Status != 'ORST_DELIVERED' (refunds/voids)
238	        // For regular orders: Status = 'ORST_DELIVERED'
239	        $query = DB::table($chainInvoiceSummaryTable)
240	            ->where('storeID', $storeID)
241	            ->where('isNoCharge', $isNoCharge);
242	
243	        // Check if isNoInvoiceSale column exists before filtering
244	        if (Schema::hasColumn($chainInvoiceSummaryTable, 'isNoInvoiceSale')) {
245	            $query->where('isNoInvoiceSale', 0);
246	        }
247	
248	        // Check if transactionType column exists and filter for regular invoices (NULL = regular POS order)
249	        if (Schema::hasColumn($chainInvoiceSummaryTable, 'transactionType')) {
250	            $query->whereNull('transactionType');
251	        }
252	
253	        if ($isRefund == 1) {
254	            $query->where('Status', '!=', 'ORST_DELIVERED');
255	        } else {
256	            $query->where('Status', 'ORST_DELIVERED');
257	        }
258	
259	        // Add reset date filter if applicable
260	        if (!empty($storeTransactionResetDate)) {
261	            $query->whereDate('orderLogTimeLocal', '>=', $storeTransactionResetDate);
262	        }
263	
264	        // Get the maximum invoice number
265	        $maxInvoiceResult = $query
266	            ->select('invoiceNumber')
267	            ->orderBy('ID', 'DESC')
268	            ->limit(1)
269	            ->first();
270	
271	        // Extract numeric part from invoice number
272	        $lastInvoiceNumber = 0;
273	        if ($maxInvoiceResult && !empty($maxInvoiceResult->invoiceNumber)) {
274	            $invoiceNumber = $maxInvoiceResult->invoiceNumber;
275	
276	            // Extract numeric part (handle formats like "STORE-123" or just "123")
277	            if (preg_match('/(\d+)$/', $invoiceNumber, $matches)) {
278	                $lastInvoiceNumber = (int)$matches[1];
279	            }
280	        }
281	
282	        $chargeType = $isNoCharge ? 'No-Charge' : 'Regular';
283	        $orderType = $isRefund ? 'Refund' : 'Order';
284	
285	        if ($dryRun) {
286	            $this->line("  [DRY RUN] Would create sequence for Chain {$chainID}, Store {$storeID}, {$chargeType} {$orderType}: {$lastInvoiceNumber}");
287	            return;
288	        }
289	
290	        // Insert or update the sequence record
291	        // Use sentinel value '1970-01-01' instead of NULL for resetDate
292	        // to ensure unique constraint works properly
293	        $sequenceData = [
294	            'storeID' => $storeID,
295	            'isNoCharge' => $isNoCharge,
296	            'isRefund' => $isRefund,
297	            'lastInvoiceNumber' => $lastInvoiceNumber,
298	            'resetDate' => $storeTransactionResetDate ?: '1970-01-01',
299	            'createdAt' => Carbon::now(),
300	            'updatedAt' => Carbon::now()
301	        ];
302	
303	        if ($existingSequence && $force) {
304	            DB::table($invoiceSequenceTable)
305	                ->where('storeID', $storeID)
306	                ->where('isNoCharge', $isNoCharge)
307	                ->where('isRefund', $isRefund)
308	                ->update([
309	                    'lastInvoiceNumber' => $lastInvoiceNumber,
310	                    'updatedAt' => Carbon::now()
311	                ]);
312	            $this->line("  âś… Updated sequence for Chain {$chainID}, Store {$storeID}, {$chargeType} {$orderType}: {$lastInvoiceNumber}");
313	        } else {
314	            DB::table($invoiceSequenceTable)->insert($sequenceData);
315	            $this->line("  âś… Created sequence for Chain {$chainID}, Store {$storeID}, {$chargeType} {$orderType}: {$lastInvoiceNumber}");
316	        }
317	
318	        $this->stats['sequences_created']++;
319	    }
