  3	namespace App\Services;
  4	
  5	use DB;
  6	use Exception;
  7	use Log;
  8	use Illuminate\Database\QueryException;
  9	
 10	class DatabaseManager
 11	{
 12	    private $maxRetries = 3;
 13	    private $initialBackoff = 500; // milliseconds
 14	    private $maxBackoff = 10000; // milliseconds
 15	    
 16	    /**
 17	     * Execute a database operation with retry logic
 18	     * 
 19	     * @param callable $operation The database operation to execute
 20	     * @param int $retries Number of retries allowed
 21	     * @param int $backoff Initial backoff in milliseconds
 22	     * @return mixed The result of the operation
 23	     * @throws Exception If the operation fails after all retries
 24	     */
 25	    public function executeWithRetry(callable $operation, $retries = null, $backoff = null)
 26	    {
 27	        $retries = $retries ?? $this->maxRetries;
 28	        $backoff = $backoff ?? $this->initialBackoff;
 29	        
 30	        $attempt = 0;
 31	        
 32	        while ($attempt <= $retries) {
 33	            try {
 34	                return $operation();
 35	            } catch (QueryException $e) {
 36	                // Check if this is a deadlock or lock wait timeout
 37	                if ($this->isDeadlockError($e) && $attempt < $retries) {
 38	                    $attempt++;
 39	                    
 40	                    // Exponential backoff with jitter
 41	                    $sleepMs = min($backoff * pow(2, $attempt) + rand(0, 100), $this->maxBackoff);
 42	                    $sleepSeconds = $sleepMs / 1000;
 43	                    
 44	                    Log::warning("Database operation failed (attempt {$attempt}/{$retries}). Retrying in {$sleepSeconds} seconds. Error: " . $e->getMessage());
 45	                    
 46	                    usleep($sleepMs * 1000); // usleep uses microseconds
 47	                    continue;
 48	                }
 49	                
 50	                // Rethrow if not a deadlock or out of retries
 51	                throw $e;
 52	            } catch (Exception $e) {
 53	                Log::error("Database operation failed: " . $e->getMessage());
 54	                throw $e;
 55	            }
 56	        }
 57	    }
 58	    
 59	    /**
 60	     * Check if the exception is a deadlock or lock wait timeout
 61	     * 
 62	     * @param QueryException $e
 63	     * @return bool
 64	     */
 65	    private function isDeadlockError(QueryException $e)
 66	    {
 67	        $errorCode = $e->getCode();
 68	        $message = $e->getMessage();
 69	        
 70	        // MySQL deadlock error code is 1213, lock wait timeout is 1205
 71	        return $errorCode == 1213 || $errorCode == 1205 || 
 72	               (stripos($message, 'deadlock') !== false) || 
 73	               (stripos($message, 'lock wait timeout') !== false);
 74	    }
