 14	    /**
 15	     * The name and signature of the console command.
 16	     *
 17	     * @var string
 18	     */
 19	    protected $signature = 'invoice:populate-sequences 
 20	                            {chainID? : Specific chain ID to process (optional)}
 21	                            {--dry-run : Show what would be done without making changes}
 22	                            {--force : Force processing even if sequences exist}';
