 42	    /**
 43	     * Execute the console command.
 44	     *
 45	     * @return mixed
 46	     */
 47	    public function handle()
 48	    {
 49	        $chainID = $this->argument('chainID');
 50	        $dryRun = $this->option('dry-run');
 51	        $force = $this->option('force');
 52	
 53	        $this->info('đźš€ Starting invoice sequence population...');
 54	        
 55	        if ($dryRun) {
 56	            $this->warn('đź”Ť DRY RUN MODE - No changes will be made');
 57	        }
 58	
 59	        try {
 60	            if ($chainID) {
 61	                $this->info("Processing specific chain: {$chainID}");
 62	
 63	                // Validate that the chain has server-generated invoice numbers enabled
 64	                $chainSetting = DB::table('chainSettings')
 65	                    ->where('chainRefID', $chainID)
 66	                    ->where('generateInvoiceNumberFromServer', 1)
 67	                    ->first();
 68	
 69	                if (!$chainSetting) {
 70	                    $this->error("Chain {$chainID} does not have generateInvoiceNumberFromServer enabled. Skipping.");
 71	                    return 1;
 72	                }
 73	
 74	                $this->processChain($chainID, $dryRun, $force);
 75	            } else {
 76	                $this->info("Processing all chains with server-generated invoice numbers...");
 77	                $this->processAllChains($dryRun, $force);
 78	            }
 79	
 80	            $this->displaySummary();
 81	            return 0;
 82	
 83	        } catch (\Exception $e) {
 84	            $this->error("Fatal error: " . $e->getMessage());
