 93	    /**
 94	     * Process all active chains
 95	     */
 96	    private function processAllChains($dryRun, $force)
 97	    {
 98	        $listOfChainsTable = Constants::getGlobalTableName("listOfChains");
 99	        $chainSettingsTable = Constants::getGlobalTableName("chainSettings");
100	
101	        $chains = DB::select("
102	            SELECT lc.chainID, lc.chainName
103	            FROM {$listOfChainsTable} lc
104	            INNER JOIN {$chainSettingsTable} cs ON lc.chainID = cs.chainRefID
105	            WHERE lc.isActive = 1
106	            AND cs.generateInvoiceNumberFromServer = 1
107	            ORDER BY lc.chainID
108	        ");
109	
110	        $this->info("Found " . count($chains) . " chains with server-generated invoice numbers");
111	
112	        $progressBar = $this->output->createProgressBar(count($chains));
113	        $progressBar->setFormat('Processing chains: %current%/%max% [%bar%] %percent:3s%% - %message%');
114	
115	        foreach ($chains as $chain) {
116	            $progressBar->setMessage("Chain {$chain->chainID} ({$chain->chainName})");
117	            $this->processChain($chain->chainID, $dryRun, $force);
118	            $this->stats['chains_processed']++;
119	            $progressBar->advance();
120	        }
121	
122	        $progressBar->finish();
123	        $this->line('');
124	    }
