129	    private function processChain($chainID, $dryRun, $force)
130	    {
131	        try {
132	            // Get chain tables
133	            $chainInvoiceSummaryTable = Constants::getChainTableName($chainID, "invoiceSummary");
134	            $invoiceSequenceTable = Constants::getChainTableName($chainID, "invoiceSequence");
135	
136	            // Check if tables exist
137	            if (!Schema::hasTable($chainInvoiceSummaryTable)) {
138	                $this->warn("  âš ď¸Ź  Chain invoice summary table does not exist: {$chainInvoiceSummaryTable}");
139	                return;
140	            }
141	
142	            if (!Schema::hasTable($invoiceSequenceTable)) {
143	                $this->warn("  âš ď¸Ź  Invoice sequence table does not exist: {$invoiceSequenceTable}");
144	                // Create the table!!
145	                $baseTable = Constants::getChainTableName(1, "invoiceSequence");
146	                $createTableQuery = createTableSchema($baseTable, $invoiceSequenceTable);
147	                $this->warn("  âš ď¸Ź  Creating table: {$createTableQuery}");
148	                if (!$dryRun) {
149	                    DB::statement($createTableQuery);
150	                }
151	            }
152	
153	            // Get stores for this chain
154	            $listOfStoresTable = Constants::getGlobalTableName("listOfStores");
155	            $stores = DB::table($listOfStoresTable)
156	                ->where('chainID', $chainID)
157	                ->where('isActive', 1)
158	                ->select('storeID', 'storeName')
159	                ->orderBy('storeID')
160	                ->get();
161	
162	            foreach ($stores as $store) {
163	                $this->processStore($chainID, $store->storeID, $chainInvoiceSummaryTable, $invoiceSequenceTable, $dryRun, $force);
164	                $this->stats['stores_processed']++;
165	            }
166	
167	        } catch (\Exception $e) {
