 53	
 54				// Get chains with fiscal year starting tomorrow
 55				$chainsWithFiscalYearTomorrow = $this->getChainsFiscalYearStartingTomorrow();
 56	
 57				if (empty($chainsWithFiscalYearTomorrow)) {
 58					$this->logger->info("No chains with fiscal year starting tomorrow");
 59					return [
 60						'status' => true,
 61						'message' => 'No chains with fiscal year starting tomorrow',
 62						'processedChains' => 0
 63					];
 64				}
 65	
 66				$processedChains = 0;
 67				$processedDevices = 0;
 68				$failedChains = [];
 69	
 70				foreach ($chainsWithFiscalYearTomorrow as $chain) {
 71					try {
 72						$this->logger->info("Processing chain {$chain->chainID} with fiscal year starting tomorrow");
 73						$result = $this->processChainFiscalYearChange($chain);
 74						$processedChains++;
 75						$processedDevices += $result['processedDevices'];
 76					} catch (Exception $e) {
 77						$this->logger->error("Error processing chain {$chain->chainID}: " . $e->getMessage());
 78						$failedChains[] = [
 79							'chainID' => $chain->chainID,
 80							'chainName' => $chain->chainName,
 81							'error' => $e->getMessage()
 82						];
 83					}
 84				}
 85	
 86				$this->logger->info("Completed daily fiscal year check. Processed {$processedChains} chains and {$processedDevices} devices.");
 87	
 88				return [
 89					'status' => true,
 90					'message' => "Processed {$processedChains} chains and {$processedDevices} devices",
 91					'processedChains' => $processedChains,
